"use client";

import { useState, useEffect } from "react";
import { motion } from "framer-motion";

type Node = {
  id: string;
  label: string;
  value: number;
  left?: Node;
  right?: Node;
};

export default function HuffmanGame() {
  const [nodes, setNodes] = useState<Node[]>([]);
  const [root, setRoot] = useState<Node | null>(null);
  const [steps, setSteps] = useState(0);
  const [errors, setErrors] = useState(0);
  const [started, setStarted] = useState(false);
  const [finished, setFinished] = useState(false);
  const [elapsed, setElapsed] = useState(0);
  const [message, setMessage] = useState<string | null>("Clique sur Commencer.");
  const [difficulty, setDifficulty] = useState<"easy" | "medium" | "hard">("easy");

  useEffect(() => {
    if (!started || finished) return;
    const timer = setInterval(() => setElapsed((e) => e + 1), 1000);
    return () => clearInterval(timer);
  }, [started, finished]);

  function generateNodes() {
    const alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZ";
    const count = difficulty === "easy" ? 4 : difficulty === "medium" ? 6 : 8;

    const list: Node[] = [];
    for (let i = 0; i < count; i++) {
      list.push({
        id: alphabet[i],
        label: alphabet[i],
        value: Math.floor(Math.random() * 40) + 5,
      });
    }

    setNodes(list.sort((a, b) => a.value - b.value));
    setRoot(null);
    setSteps(0);
    setErrors(0);
    setElapsed(0);
    setStarted(true);
    setFinished(false);
    setMessage("Glisse un nœud sur un autre pour les fusionner.");
  }

  function combine(a: Node, b: Node) {
    const sorted = [...nodes].sort((x, y) => x.value - y.value);
    const small1 = sorted[0];
    const small2 = sorted[1];

    const isValid =
      (a.value === small1.value && b.value === small2.value) ||
      (b.value === small1.value && a.value === small2.value);

    if (!isValid) {
      setErrors((e) => e + 1);
      setMessage("❌ Mauvais choix : prends les deux plus petites valeurs.");
      return;
    }

    const newNode: Node = {
      id: a.id + b.id,
      label: `${a.label}+${b.label}`,
      value: a.value + b.value,
      left: a,
      right: b,
    };

    const updated = nodes
      .filter((n) => n.id !== a.id && n.id !== b.id)
      .concat(newNode)
      .sort((x, y) => x.value - y.value);

    setNodes(updated);
    setSteps((s) => s + 1);
    setMessage("✔ Bonne fusion ! Continue.");

    if (updated.length === 1) {
      setFinished(true);
      setRoot(newNode);
      setMessage("🎉 Arbre de Huffman terminé !");
    }
  }

  function handleDrop(e: any, src: Node) {
    const point = document.elementFromPoint(e.clientX, e.clientY);
    const target = point?.closest("[data-node-id]") as HTMLElement | null;
    if (!target) return;
    const targetId = target.dataset.nodeId;
    if (targetId === src.id) return;

    const tgt = nodes.find((n) => n.id === targetId);
    if (tgt) combine(src, tgt);
  }

  function renderTree(node: Node | null): JSX.Element | null {
    if (!node) return null;
    const isLeaf = !node.left && !node.right;

    return (
      <div className="flex flex-col items-center">
        <motion.div
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          className={`px-3 py-2 rounded-lg border mb-2 ${
            isLeaf
              ? "bg-emerald-500/20 border-emerald-300/50"
              : "bg-white/10 border-white/20"
          }`}
        >
          <div className="font-semibold">{node.label}</div>
          <div className="text-xs text-white/70">{node.value}</div>
        </motion.div>

        {(node.left || node.right) && (
          <div className="flex items-start gap-6">
            <div className="flex flex-col items-center">
              <div className="text-xs text-white/50">0</div>
              {renderTree(node.left!)}
            </div>
            <div className="flex flex-col items-center">
              <div className="text-xs text-white/50">1</div>
              {renderTree(node.right!)}
            </div>
          </div>
        )}
      </div>
    );
  }

  const score = Math.max(
    0,
    1000 - steps * 20 - errors * 40 - elapsed * 2
  );

  return (
    <div className="text-white">

      {/* Header */}
      <div className="flex justify-between items-center mb-6">
        <div>
          <h1 className="text-3xl font-bold">Jeu Huffman</h1>
          <p className="text-white/70 text-sm">{message}</p>
        </div>

        <div className="flex items-center gap-2">
          <button
            className={`px-4 py-2 rounded-xl border ${
              difficulty === "easy"
                ? "bg-white text-black"
                : "bg-white/5 border-white/20"
            }`}
            onClick={() => setDifficulty("easy")}
            disabled={started && !finished}
          >
            Facile
          </button>
          <button
            className={`px-4 py-2 rounded-xl border ${
              difficulty === "medium"
                ? "bg-white text-black"
                : "bg-white/5 border-white/20"
            }`}
            onClick={() => setDifficulty("medium")}
            disabled={started && !finished}
          >
            Moyen
          </button>
          <button
            className={`px-4 py-2 rounded-xl border ${
              difficulty === "hard"
                ? "bg-white text-black"
                : "bg-white/5 border-white/20"
            }`}
            onClick={() => setDifficulty("hard")}
            disabled={started && !finished}
          >
            Difficile
          </button>

          <button
            onClick={generateNodes}
            className="ml-4 px-4 py-2 rounded-xl bg-white text-black font-semibold"
          >
            {started ? "Recommencer" : "Commencer"}
          </button>
        </div>
      </div>

      {/* Stats */}
      {started && (
        <div className="grid grid-cols-4 gap-3 mb-6">
          <Stat label="Temps" value={elapsed + " sec"} />
          <Stat label="Fusions" value={steps} />
          <Stat label="Erreurs" value={errors} color="text-red-300" />
          <Stat label="Score" value={score} color="text-emerald-300" />
        </div>
      )}

      {/* Content */}
      <div className="grid lg:grid-cols-2 gap-8">

        {/* Nœuds */}
        <div className="bg-white/5 border border-white/10 rounded-3xl p-6">
          <h2 className="text-xl font-semibold mb-4">Nœuds</h2>
          <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
            {nodes.map((node) => (
              <motion.div
                key={node.id}
                drag
                dragMomentum={false}
                onDragEnd={(e) => handleDrop(e, node)}
                data-node-id={node.id}
                whileHover={{ scale: 1.05 }}
                className="p-4 rounded-xl bg-white/10 border border-white/20 cursor-grab active:cursor-grabbing"
              >
                <div className="font-semibold">{node.label}</div>
                <div className="text-sm text-white/70">{node.value}</div>
              </motion.div>
            ))}
          </div>
        </div>

        {/* Arbre final */}
        <div className="bg-white/5 border border-white/10 rounded-3xl p-6">
          <h2 className="text-xl font-semibold mb-4">Arbre de Huffman</h2>
          {renderTree(root)}
        </div>
      </div>

      {finished && (
        <div className="mt-6 p-4 rounded-xl bg-emerald-500/20 border border-emerald-300/40">
          🎉 Bravo ! Arbre terminé — Score : {score}
        </div>
      )}
    </div>
  );
}

// Petit composant pour stats
function Stat({ label, value, color }: any) {
  return (
    <div className="bg-white/5 border border-white/20 rounded-2xl px-3 py-2">
      <div className="text-xs text-white/60">{label}</div>
      <div className={`text-lg font-semibold ${color || ""}`}>{value}</div>
    </div>
  );
}
